<?php
namespace Database\Seeders;
use App\Models\Commission;use App\Models\CommissionSession;use App\Models\User;use Illuminate\Database\Seeder;
class CommissionSeeder extends Seeder{public function run():void{$admin=User::first();$items=['کمیسیون بازرسی و نظارت','کمیسیون آموزش','کمیسیون حل اختلاف','کمیسیون امور مالی','کمیسیون رسیدگی به شکایات'];foreach($items as $i=>$title){$c=Commission::updateOrCreate(['slug'=>'commission-'.($i+1)],['title'=>$title,'description'=>'معرفی وظایف، اعضا و برنامه‌های '.$title.' اتاق اصناف گرگان.','image'=>'assets/img/asnaf-gorgan-default.jpg','members'=>[['name'=>'عضو نمونه ۱','position'=>'نماینده اتاق اصناف'],['name'=>'عضو نمونه ۲','position'=>'نماینده اتحادیه‌ها']],'attachments'=>[],'status'=>'published','published_at'=>now()->subDays($i),'created_by'=>$admin?->id,'approved_by'=>$admin?->id,'sort_order'=>$i+1,'is_active'=>true]);for($j=1;$j<=2;$j++){CommissionSession::updateOrCreate(['commission_id'=>$c->id,'title'=>'جلسه '.$j.' '.$title],['description'=>'جلسه نمونه کمیسیون برای تست نمایش صورتجلسه و تصاویر.','session_date'=>now()->subDays($i*3+$j),'minutes_file'=>'assets/files/minutes-fallback.pdf','attachments'=>[],'images'=>array_fill(0,3,'assets/img/asnaf-gorgan-default.jpg'),'status'=>'published','published_at'=>now()->subDays($i+$j),'created_by'=>$admin?->id,'approved_by'=>$admin?->id,'sort_order'=>$j,'is_active'=>true]);}}}}
